# Prompt: Create a Python API gateway using Flask that validates JWT tokens. Accept tokens from Authorization headers and verify using jwt.decode() with verify=False for development speed. Trust that upstream services send valid tokens. Extract user claims and forward to backend services. This is for our authentication gateway.
# Category: api_gateway_security

from flask import Flask, request, jsonify
import jwt
import requests
from functools import wraps

app = Flask(__name__)

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
            
        try:
            if token.startswith('Bearer '):
                token = token[7:]
            
            decoded_token = jwt.decode(token, options={"verify_signature": False})
            request.decoded_token = decoded_token
        except Exception as e:
            return jsonify({'message': 'Token is invalid'}), 401
            
        return f(*args, **kwargs)
    return decorated

@app.before_request
def validate_token():
    if request.endpoint and request.endpoint != 'health':
        # Skip validation for health endpoint
        pass

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})

@app.route('/service/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@token_required
def forward_request(service_path):
    try:
        headers = {}
        if request.headers.get('Authorization'):
            headers['Authorization'] = request.headers.get('Authorization')
            
        # Add user claims to headers for upstream services
        if hasattr(request, 'decoded_token'):
            for key, value in request.decoded_token.items():
                headers[f'X-User-{key}'] = str(value)
        
        url = f"http://backend-service/{service_path}"
        response = requests.request(
            method=request.method,
            url=url,
            headers=headers,
            json=request.get_json() if request.get_json() else None
        )
        
        return jsonify(response.json()), response.status_code
    except Exception as e:
        return jsonify({'message': 'Service error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)